// Construir nueva entry y preparar payload para PUT
const form = $('Form Trigger').first().json;
const fileResp = $input.first().json;

const current = JSON.parse(
  Buffer.from(fileResp.content, 'base64').toString('utf-8')
);

// Construir entry
const version = String(form['Versión (ej: v3.9.1)']).trim();
const id = version.replace(/[^a-zA-Z0-9]+/g, '-').toLowerCase().replace(/^-|-$/g, '');
const dateISO = form['Fecha']; // YYYY-MM-DD
const d = new Date(dateISO);
const MESES = ['Ene','Feb','Mar','Abr','May','Jun','Jul','Ago','Sep','Oct','Nov','Dic'];
const MESES_LARGO = ['Enero','Febrero','Marzo','Abril','Mayo','Junio','Julio','Agosto','Septiembre','Octubre','Noviembre','Diciembre'];
const date = `${String(d.getUTCDate()).padStart(2,'0')} ${MESES[d.getUTCMonth()]} ${d.getUTCFullYear()}`;
const month = `${MESES_LARGO[d.getUTCMonth()]} ${d.getUTCFullYear()}`;

const tags = [form['Tipo principal']];
const t2 = form['Tipo secundario (opcional)'];
if (t2 && t2 !== form['Tipo principal']) tags.push(t2);

const points = String(form['Puntos (uno por línea, formato: Título: descripción)'])
  .split(/\r?\n/)
  .map(l => l.trim())
  .filter(Boolean)
  .map(line => {
    const idx = line.indexOf(':');
    if (idx === -1) return { b: line, t: '' };
    return { b: line.slice(0, idx).trim(), t: line.slice(idx+1).trim() };
  });

const entry = {
  id,
  version,
  date,
  dateISO,
  month,
  featured: form['¿Destacar como featured?'] === 'sí',
  tags,
  title: form['Título'],
  lede: form['Lede (resumen 1-2 frases)'],
  media: { kind: 'screenshot', label: form['Título'] },
  points,
  author: {
    name: form['Autor (nombre)'],
    initials: String(form['Iniciales autor (2 letras)']).toUpperCase().slice(0,2)
  },
  readTime: form['Tiempo de lectura'] || '3 min'
};

// Si ya existe el id, lo reemplazamos; si no, lo añadimos al principio
const existingIdx = current.findIndex(e => e.id === entry.id);
let updated;
if (existingIdx >= 0) {
  updated = [...current];
  updated[existingIdx] = entry;
} else {
  updated = [entry, ...current];
}

const newContent = JSON.stringify(updated, null, 2) + '\n';
const newBase64 = Buffer.from(newContent, 'utf-8').toString('base64');

return [{ json: {
  sha: fileResp.sha,
  content: newBase64,
  message: `changelog: ${existingIdx >= 0 ? 'update' : 'publish'} ${version} — ${entry.title}`,
  entryId: entry.id,
  isUpdate: existingIdx >= 0
}}];

